int main() {
    std::cout << "--- Testing Counter class ---" << std::endl;

    Counter c1(0);
    std::cout << "Initial c1: " << c1.getCount() << std::endl;

    // Test Prefix Increment
    Counter& c1_ref = ++c1;
    std::cout << "After ++c1: c1 = " << c1.getCount() << ", c1_ref = " << c1_ref.getCount() << std::endl;

    // Test Postfix Increment
    Counter c2(5);
    std::cout << "Initial c2: " << c2.getCount() << std::endl;
    Counter c2_old_value = c2++;
    std::cout << "After c2++: c2 = " << c2.getCount() << ", c2_old_value = " << c2_old_value.getCount() << std::endl;

    // Test Chaining Prefix Increment
    Counter c3(10);
    std::cout << "Initial c3: " << c3.getCount() << std::endl;
    Counter& c3_ref2 = ++(++c3);
    std::cout << "After ++(++c3): c3 = " << c3.getCount() << ", c3_ref2 = " << c3_ref2.getCount() << std::endl;

    // Test Chaining Postfix Increment
    Counter c4(15);
    std::cout << "Initial c4: " << c4.getCount() << std::endl;
    Counter c4_val = c4++;
    std::cout << "After c4++: c4 = " << c4.getCount() << ", c4_val = " << c4_val.getCount() << std::endl;

    return 0;
}
